import { t as db } from "../../../chunks/db.js";
import { t as WalletService } from "../../../chunks/wallet.service.js";
import { redirect } from "@sveltejs/kit";
//#region src/routes/wallet/+page.server.ts
var load = async ({ locals }) => {
	if (!locals.user) throw redirect(303, "/auth/login");
	return {
		balance: await WalletService.getBalance(locals.user.id),
		transactions: (await db.transaction.findMany({
			where: { profileId: locals.user.id },
			orderBy: { createdAt: "desc" },
			take: 5
		})).map((tx) => ({
			...tx,
			amount: Number(tx.amount)
		}))
	};
};
//#endregion
export { load };
